firmware_template.source:
#include "secure_boot.h"
#include <esp_secure_boot.h>
#include <esp_flash_encrypt.h>

void secure_boot_setup() {
    print_security_status();
}

bool is_secure_boot_enabled() {
    return esp_secure_boot_enabled();
}

bool is_flash_encrypted() {
    return esp_flash_encryption_enabled();
}

void print_security_status() {
    Serial.println("[security] === Security Status ===");
    Serial.printf("[security] Secure Boot: %s\n", is_secure_boot_enabled() ? "ENABLED" : "DISABLED");
    Serial.printf("[security] Flash Encryption: %s\n", is_flash_encrypted() ? "ENABLED" : "DISABLED");
    Serial.printf("[security] Chip revision: %d\n", ESP.getChipRevision());
    Serial.printf("[security] SDK version: %s\n", ESP.getSdkVersion());
    Serial.println("[security] ========================");
}
